from flask import Flask, request, jsonify
import redis
import re

app = Flask(__name__)
r = redis.Redis(host='localhost', port=6379, db=0)

# Regex to allow only safe Redis commands
SAFE_COMMANDS = re.compile(r'^(GET|SET|DEL|EXISTS|KEYS|FLUSHDB|HGET|HSET|LPUSH|LRANGE|SADD|SMEMBERS|ZADD|ZRANGE|PING)$', re.IGNORECASE)

@app.route('/execute', methods=['GET'])
def execute_command():
    command = request.args.get('command')
    
    if not command or not SAFE_COMMANDS.match(command.split()[0]):
        return jsonify({'error': 'Invalid command'}), 400

    try:
        result = r.execute_command(command)
        return jsonify({'result': result}), 200
    except redis.RedisError as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=False)